+                    txn_id = %txn_id,
+                    elapsed_ms = start.elapsed().as_millis(),
+                    "serialized writer drain complete"
+                );
+                return Ok(());
+            }
+
+            if start.elapsed() >= timeout {
+                tracing::warn!(
