+    /// - Acquire-load the token.
+    /// - If stale, CAS-clear with AcqRel.
+    /// - Retry on CAS races.
+    pub fn check_serialized_writer_exclusion(
+        &self,
+        now_epoch_secs: u64,
+        process_alive: impl Fn(u32, u64) -> bool,
+    ) -> Result<(), MvccError> {
